public class MdbxFfiException: UniffiException {
    MdbxFfiException() : base() {}
    MdbxFfiException(String @Message) : base(@Message) {}

    // Each variant is a nested class
    
    
    public class Storage : MdbxFfiException {
        // Members
        public string @message;

        // Constructor
        public Storage(
                string @message) : base(
                "@message" + "=" + @message) {

            this.@message = @message;
        }
    }
    
    
    public class Serialization : MdbxFfiException {
        // Members
        public string @message;

        // Constructor
        public Serialization(
                string @message) : base(
                "@message" + "=" + @message) {

            this.@message = @message;
        }
    }
    
    
    public class InvalidEntryType : MdbxFfiException {
        // Members
        public string @entryType;

        // Constructor
        public InvalidEntryType(
                string @entryType) : base(
                "@entryType" + "=" + @entryType) {

            this.@entryType = @entryType;
        }
    }
    
    
    public class LockPoisoned : MdbxFfiException {
        public LockPoisoned() : base() {}
    }
    
    

    
}

class FfiConverterTypeMdbxFfiError : FfiConverterRustBuffer<MdbxFfiException>, CallStatusErrorHandler<MdbxFfiException> {
    public static FfiConverterTypeMdbxFfiError INSTANCE = new FfiConverterTypeMdbxFfiError();

    public override MdbxFfiException Read(BigEndianStream stream) {
        var value = stream.ReadInt();
        switch (value) {
            case 1:
                return new MdbxFfiException.Storage(
                    FfiConverterString.INSTANCE.Read(stream));
            case 2:
                return new MdbxFfiException.Serialization(
                    FfiConverterString.INSTANCE.Read(stream));
            case 3:
                return new MdbxFfiException.InvalidEntryType(
                    FfiConverterString.INSTANCE.Read(stream));
            case 4:
                return new MdbxFfiException.LockPoisoned();
            default:
                throw new InternalException(String.Format("invalid error value '{0}' in FfiConverterTypeMdbxFfiError.Read()", value));
        }
    }

    public override int AllocationSize(MdbxFfiException value) {
        switch (value) {

            case MdbxFfiException.Storage variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@message);

            case MdbxFfiException.Serialization variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@message);

            case MdbxFfiException.InvalidEntryType variant_value:
                return 4
                    + FfiConverterString.INSTANCE.AllocationSize(variant_value.@entryType);

            case MdbxFfiException.LockPoisoned variant_value:
                return 4;
            default:
                throw new InternalException(String.Format("invalid error value '{0}' in FfiConverterTypeMdbxFfiError.AllocationSize()", value));
        }
    }

    public override void Write(MdbxFfiException value, BigEndianStream stream) {
        switch (value) {
            case MdbxFfiException.Storage variant_value:
                stream.WriteInt(1);
                FfiConverterString.INSTANCE.Write(variant_value.@message, stream);
                break;
            case MdbxFfiException.Serialization variant_value:
                stream.WriteInt(2);
                FfiConverterString.INSTANCE.Write(variant_value.@message, stream);
                break;
            case MdbxFfiException.InvalidEntryType variant_value:
                stream.WriteInt(3);
                FfiConverterString.INSTANCE.Write(variant_value.@entryType, stream);
                break;
            case MdbxFfiException.LockPoisoned variant_value:
                stream.WriteInt(4);
                break;
            default:
                throw new InternalException(String.Format("invalid error value '{0}' in FfiConverterTypeMdbxFfiError.Write()", value));
        }
    }
}





